package github.chains;

import com.github.javaparser.StaticJavaParser;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.ImportDeclaration;
import com.github.javaparser.ast.NodeList;
import com.github.javaparser.ast.expr.Name;
import com.github.javaparser.ast.expr.SimpleName;
import com.github.javaparser.ast.nodeTypes.NodeWithImports;
import com.github.javaparser.ast.stmt.ImportDeclaration;
import com.github.javaparser.ast.visitor.ModifierVisitor;
import com.github.javaparser.ast.visitor.Visitable;
import com.github.javaparser.utils.Log;

import java.io.FileInputStream;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) throws IOException {
        // Set log level to see what's happening
        Log.setAdapter(new Log.StandardOutLoggerAdapter());

        // Read the source directory
        String sourceDir = args.length > 0 ? args[0] : "/workspace/open-pdf-sign/src/main/java";

        // Create the transformation visitor
        CertificationPermissionFixVisitor visitor = new CertificationPermissionFixVisitor();

        // Process all Java files in the directory
        Files.walk(Paths.get(sourceDir))
                .filter(path -> path.toString().endsWith(".java"))
                .forEach(path -> {
                    try {
                        System.out.println("Processing: " + path);
                        CompilationUnit cu = StaticJavaParser.parse(new FileInputStream(path.toFile()));
                        cu.accept(visitor, null);
                        cu.save(path.toFile());
                    } catch (Exception e) {
                        System.err.println("Error processing " + path + ": " + e.getMessage());
                        e.printStackTrace();
                    }
                });
    }

    static class CertificationPermissionFixVisitor extends ModifierVisitor<Void> {
        @Override
        public Visitable visit(ImportDeclaration importDeclaration, Void arg) {
            // Check if this is the old import that needs to be replaced
            if (importDeclaration.getNameAsString().equals("eu.europa.esig.dss.pades.CertificationPermission")) {
                // Replace with the new import
                importDeclaration.setName(new Name("eu.europa.esig.dss.enumerations.CertificationPermission"));
            }
            return super.visit(importDeclaration, arg);
        }

        @Override
        public Visitable visit(com.github.javaparser.ast.expr.Name name, Void arg) {
            // Replace references to CertificationPermission in code
            if (name.getIdentifier().equals("CertificationPermission")) {
                // Check if we're in a qualified name context
                if (name.getParentNode().isPresent()) {
                    // Check if it's a qualified name like pades.CertificationPermission
                    if (name.getParentNode().get() instanceof com.github.javaparser.ast.expr.QualifiedName) {
                        com.github.javaparser.ast.expr.QualifiedName qualifiedName = (com.github.javaparser.ast.expr.QualifiedName) name.getParentNode().get();
                        if (qualifiedName.getQualifier().toString().equals("pades")) {
                            // Replace the qualified name with the new package
                            return new com.github.javaparser.ast.expr.Name("eu.europa.esig.dss.enumerations.CertificationPermission");
                        }
                    }
                }
            }
            return super.visit(name, arg);
        }
    }
}

